import{CByte,PacketHeader}from"../constants";import{toShort}from"./bufferUtil";export function analysePacket(packet,ignoreLengthMismatch=false){if(!PacketHeader.matches(packet)){console.warn("Ignoring irrelevant packet",packet);return[null,null]}const payloadLength=packet.slice(4,6).readUInt16LE();if(payloadLength+6!==packet.length){if(!ignoreLengthMismatch){console.warn(`Packet is meant to be ${payloadLength+6} bytes long, but is actually ${packet.length} bytes long`);return[null,null]}}return[packet.slice(6,8).toString(),packet.slice(12)]}export function createPacket(messageCode,data,customA,customB){if(!data)data=Buffer.allocUnsafe(0);const connIdentity=Buffer.from([customA??CByte.A,0,customB??CByte.B,0]);if(connIdentity.length!==4)throw Error("connIdentity");const lengthLE=toShort(messageCode.length+connIdentity.length+data.length);if(lengthLE.length!==2)throw Error("lengthLE");const b=Buffer.alloc(PacketHeader.length+lengthLE.length+messageCode.length+connIdentity.length+data.length);let cursor=0;b.fill(PacketHeader);b.fill(lengthLE,cursor+=PacketHeader.length);b.write(typeof messageCode==="string"?messageCode:messageCode.toString("utf8"),cursor+=lengthLE.length);b.fill(connIdentity,cursor+=messageCode.length);if(typeof data==="string")b.write(data,cursor+=connIdentity.length);else b.fill(data,cursor+=connIdentity.length);return b}